"""
Backend-neutral test doubles for the HTTP client wrapper and its responses.

These mirror the frozen surface in `http_protocol.py` so tests can exercise the
capabilities integrations rely on (connection close, cookie access, env-trust)
without binding to a specific backend (`requests`/`httpx`).
"""

from __future__ import annotations

import json as _json
from typing import Any, Iterator


class MockHTTPResponse:
    """Backend-neutral response satisfying `HTTPResponseProtocol`."""

    def __init__(
        self,
        content: bytes | str = b'',
        status_code: int = 200,
        headers: dict[str, str] | None = None,
        encoding: str | None = None,
        json_data: Any = None,
    ) -> None:
        if json_data is not None:
            content = _json.dumps(json_data).encode('utf-8')
        self._content = content.encode('utf-8') if isinstance(content, str) else content
        self._status_code = status_code
        self._headers = dict(headers or {})
        self._encoding = encoding
        self.closed = False

    @property
    def content(self) -> bytes:
        return self._content

    @property
    def headers(self) -> dict[str, str]:
        return self._headers

    @property
    def encoding(self) -> str | None:
        return self._encoding

    @encoding.setter
    def encoding(self, value: str | None) -> None:
        self._encoding = value

    @property
    def status_code(self) -> int:
        return self._status_code

    def iter_content(self, chunk_size: int | None = None, decode_unicode: bool = False) -> Iterator[Any]:
        data: Any = self._content.decode(self._encoding or 'utf-8') if decode_unicode else self._content
        yield data

    def iter_lines(
        self,
        chunk_size: int | None = None,
        decode_unicode: bool = False,
        delimiter: bytes | None = None,
    ) -> Iterator[Any]:
        data = self._content.decode(self._encoding or 'utf-8') if decode_unicode else self._content
        sep: Any = (delimiter or b'\n') if not decode_unicode else (delimiter or b'\n').decode('utf-8')
        for line in data.split(sep):
            yield line

    def raise_for_status(self) -> None:
        if self._status_code >= 400:
            raise AssertionError('status {}'.format(self._status_code))

    def json(self, **kwargs: Any) -> Any:
        return _json.loads(self._content.decode(self._encoding or 'utf-8'), **kwargs)

    def close(self) -> None:
        self.closed = True

    def __enter__(self) -> "MockHTTPResponse":
        return self

    def __exit__(self, *args: Any) -> None:
        self.close()


class MockHTTPClient:
    """Backend-neutral client satisfying `HTTPClientProtocol`."""

    def __init__(
        self,
        response: MockHTTPResponse | None = None,
        cookies: dict[str, str] | None = None,
        trust_env: bool = True,
    ) -> None:
        self.options: dict[str, Any] = {}
        self._response = response if response is not None else MockHTTPResponse()
        self._cookies = dict(cookies or {})
        self._trust_env = trust_env
        self.closed = False

    def _request(self, method: str, url: str, **options: Any) -> MockHTTPResponse:
        return self._response

    def get(self, url: str, **options: Any) -> MockHTTPResponse:
        return self._request('get', url, **options)

    def post(self, url: str, **options: Any) -> MockHTTPResponse:
        return self._request('post', url, **options)

    def head(self, url: str, **options: Any) -> MockHTTPResponse:
        return self._request('head', url, **options)

    def put(self, url: str, **options: Any) -> MockHTTPResponse:
        return self._request('put', url, **options)

    def patch(self, url: str, **options: Any) -> MockHTTPResponse:
        return self._request('patch', url, **options)

    def delete(self, url: str, **options: Any) -> MockHTTPResponse:
        return self._request('delete', url, **options)

    def options_method(self, url: str, **options: Any) -> MockHTTPResponse:
        return self._request('options', url, **options)

    def handle_auth_token(self, **request: Any) -> None:
        pass

    def close(self) -> None:
        self.closed = True

    def get_cookie(self, name: str, default: str | None = None) -> str | None:
        return self._cookies.get(name, default)

    @property
    def trust_env(self) -> bool:
        return self._trust_env

    @trust_env.setter
    def trust_env(self, value: bool) -> None:
        self._trust_env = bool(value)

